22: public class SaslConfigs {
23: 
24:     private static final String OAUTHBEARER_NOTE = " Currently applies only to OAUTHBEARER.";
25: 
26:     /*
27:      * NOTE: DO NOT CHANGE EITHER CONFIG NAMES AS THESE ARE PART OF THE PUBLIC API AND CHANGE WILL BREAK USER CODE.
28:      */
29:     /** SASL mechanism configuration - standard mechanism names are listed <a href="http://www.iana.org/assignments/sasl-mechanisms/sasl-mechanisms.xhtml">here</a>. */
30:     public static final String SASL_MECHANISM = "sasl.mechanism";
31:     public static final String SASL_MECHANISM_DOC = "SASL mechanism used for client connections. This may be any mechanism for which a security provider is available. GSSAPI is the default mechanism.";
32:     public static final String GSSAPI_MECHANISM = "GSSAPI";
33:     public static final String DEFAULT_SASL_MECHANISM = GSSAPI_MECHANISM;
34: 
35:     public static final String SASL_JAAS_CONFIG = "sasl.jaas.config";
36:     public static final String SASL_JAAS_CONFIG_DOC = "JAAS login context parameters for SASL connections in the format used by JAAS configuration files. "
37:         + "JAAS configuration file format is described <a href=\"https://docs.oracle.com/javase/8/docs/technotes/guides/security/jgss/tutorials/LoginConfigFile.html\">here</a>. "
38:         + "The format for the value is: <code>loginModuleClass controlFlag (optionName=optionValue)*;</code>. For brokers, "
39:         + "the config must be prefixed with listener prefix and SASL mechanism name in lower-case. For example, "
40:         + "listener.name.sasl_ssl.scram-sha-256.sasl.jaas.config=com.example.ScramLoginModule required;";
41: 
42:     public static final String SASL_CLIENT_CALLBACK_HANDLER_CLASS = "sasl.client.callback.handler.class";
43:     public static final String SASL_CLIENT_CALLBACK_HANDLER_CLASS_DOC = "The fully qualified name of a SASL client callback handler class "
44:         + "that implements the AuthenticateCallbackHandler interface.";
45: 
46:     public static final String SASL_LOGIN_CALLBACK_HANDLER_CLASS = "sasl.login.callback.handler.class";
47:     public static final String SASL_LOGIN_CALLBACK_HANDLER_CLASS_DOC = "The fully qualified name of a SASL login callback handler class "
48:             + "that implements the AuthenticateCallbackHandler interface. For brokers, login callback handler config must be prefixed with "
49:             + "listener prefix and SASL mechanism name in lower-case. For example, "
50:             + "listener.name.sasl_ssl.scram-sha-256.sasl.login.callback.handler.class=com.example.CustomScramLoginCallbackHandler";
51: 
52:     public static final String SASL_LOGIN_CLASS = "sasl.login.class";
53:     public static final String SASL_LOGIN_CLASS_DOC = "The fully qualified name of a class that implements the Login interface. "
54:         + "For brokers, login config must be prefixed with listener prefix and SASL mechanism name in lower-case. For example, "
55:         + "listener.name.sasl_ssl.scram-sha-256.sasl.login.class=com.example.CustomScramLogin";
56: 
57:     public static final String SASL_KERBEROS_SERVICE_NAME = "sasl.kerberos.service.name";
58:     public static final String SASL_KERBEROS_SERVICE_NAME_DOC = "The Kerberos principal name that Kafka runs as. "
59:         + "This can be defined either in Kafka's JAAS config or in Kafka's config.";
60: 
61:     public static final String SASL_KERBEROS_KINIT_CMD = "sasl.kerberos.kinit.cmd";
62:     public static final String SASL_KERBEROS_KINIT_CMD_DOC = "Kerberos kinit command path.";
63:     public static final String DEFAULT_KERBEROS_KINIT_CMD = "/usr/bin/kinit";
64: 
65:     public static final String SASL_KERBEROS_TICKET_RENEW_WINDOW_FACTOR = "sasl.kerberos.ticket.renew.window.factor";
66:     public static final String SASL_KERBEROS_TICKET_RENEW_WINDOW_FACTOR_DOC = "Login thread will sleep until the specified window factor of time from last refresh"
67:         + " to ticket's expiry has been reached, at which time it will try to renew the ticket.";
68:     public static final double DEFAULT_KERBEROS_TICKET_RENEW_WINDOW_FACTOR = 0.80;
69: 
70:     public static final String SASL_KERBEROS_TICKET_RENEW_JITTER = "sasl.kerberos.ticket.renew.jitter";
71:     public static final String SASL_KERBEROS_TICKET_RENEW_JITTER_DOC = "Percentage of random jitter added to the renewal time.";
72:     public static final double DEFAULT_KERBEROS_TICKET_RENEW_JITTER = 0.05;
73: 
74:     public static final String SASL_KERBEROS_MIN_TIME_BEFORE_RELOGIN = "sasl.kerberos.min.time.before.relogin";
75:     public static final String SASL_KERBEROS_MIN_TIME_BEFORE_RELOGIN_DOC = "Login thread sleep time between refresh attempts.";
76:     public static final long DEFAULT_KERBEROS_MIN_TIME_BEFORE_RELOGIN = 1 * 60 * 1000L;
77: 
78:     public static final String SASL_LOGIN_REFRESH_WINDOW_FACTOR = "sasl.login.refresh.window.factor";
79:     public static final String SASL_LOGIN_REFRESH_WINDOW_FACTOR_DOC = "Login refresh thread will sleep until the specified window factor relative to the"
80:             + " credential's lifetime has been reached, at which time it will try to refresh the credential."
81:             + " Legal values are between 0.5 (50%) and 1.0 (100%) inclusive; a default value of 0.8 (80%) is used"
82:             + " if no value is specified."
83:             + OAUTHBEARER_NOTE;
84:     public static final double DEFAULT_LOGIN_REFRESH_WINDOW_FACTOR = 0.80;
85: 
86:     public static final String SASL_LOGIN_REFRESH_WINDOW_JITTER = "sasl.login.refresh.window.jitter";
87:     public static final String SASL_LOGIN_REFRESH_WINDOW_JITTER_DOC = "The maximum amount of random jitter relative to the credential's lifetime"
88:             + " that is added to the login refresh thread's sleep time. Legal values are between 0 and 0.25 (25%) inclusive;"
89:             + " a default value of 0.05 (5%) is used if no value is specified."
90:             + OAUTHBEARER_NOTE;
91:     public static final double DEFAULT_LOGIN_REFRESH_WINDOW_JITTER = 0.05;
92: 
93:     public static final String SASL_LOGIN_REFRESH_MIN_PERIOD_SECONDS = "sasl.login.refresh.min.period.seconds";
94:     public static final String SASL_LOGIN_REFRESH_MIN_PERIOD_SECONDS_DOC = "The desired minimum time for the login refresh thread to wait before refreshing a credential,"
95:             + " in seconds. Legal values are between 0 and 900 (15 minutes); a default value of 60 (1 minute) is used if no value is specified.  This value and "
96:             + " sasl.login.refresh.buffer.seconds are both ignored if their sum exceeds the remaining lifetime of a credential."
97:             + OAUTHBEARER_NOTE;
98:     public static final short DEFAULT_LOGIN_REFRESH_MIN_PERIOD_SECONDS = 60;
99: 
100:     public static final String SASL_LOGIN_REFRESH_BUFFER_SECONDS = "sasl.login.refresh.buffer.seconds";
101:     public static final String SASL_LOGIN_REFRESH_BUFFER_SECONDS_DOC = "The amount of buffer time before credential expiration to maintain when refreshing a credential,"
102:             + " in seconds. If a refresh would otherwise occur closer to expiration than the number of buffer seconds then the refresh will be moved up to maintain"
103:             + " as much of the buffer time as possible. Legal values are between 0 and 3600 (1 hour); a default value of  300 (5 minutes) is used if no value is specified."
104:             + " This value and sasl.login.refresh.min.period.seconds are both ignored if their sum exceeds the remaining lifetime of a credential."
105:             + OAUTHBEARER_NOTE;
106:     public static final short DEFAULT_LOGIN_REFRESH_BUFFER_SECONDS = 300;
107: 
108:     public static final String SASL_LOGIN_CONNECT_TIMEOUT_MS = "sasl.login.connect.timeout.ms";
109:     public static final String SASL_LOGIN_CONNECT_TIMEOUT_MS_DOC = "The (optional) value in milliseconds for the external authentication provider connection timeout."
110:             + OAUTHBEARER_NOTE;
111: 
112:     public static final String SASL_LOGIN_READ_TIMEOUT_MS = "sasl.login.read.timeout.ms";
113:     public static final String SASL_LOGIN_READ_TIMEOUT_MS_DOC = "The (optional) value in milliseconds for the external authentication provider read timeout."
114:             + OAUTHBEARER_NOTE;
115: 
116:     private static final String LOGIN_EXPONENTIAL_BACKOFF_NOTE = " Login uses an exponential backoff algorithm with an initial wait based on the"
117:             + " sasl.login.retry.backoff.ms setting and will double in wait length between attempts up to a maximum wait length specified by the"
118:             + " sasl.login.retry.backoff.max.ms setting."
119:             + OAUTHBEARER_NOTE;
120: 
121:     public static final String SASL_LOGIN_RETRY_BACKOFF_MAX_MS = "sasl.login.retry.backoff.max.ms";
122:     public static final long DEFAULT_SASL_LOGIN_RETRY_BACKOFF_MAX_MS = 10000;
123:     public static final String SASL_LOGIN_RETRY_BACKOFF_MAX_MS_DOC = "The (optional) value in milliseconds for the maximum wait between login attempts to the"
124:             + " external authentication provider."
125:             + LOGIN_EXPONENTIAL_BACKOFF_NOTE;
126: 
127:     public static final String SASL_LOGIN_RETRY_BACKOFF_MS = "sasl.login.retry.backoff.ms";
128:     public static final long DEFAULT_SASL_LOGIN_RETRY_BACKOFF_MS = 100;
129:     public static final String SASL_LOGIN_RETRY_BACKOFF_MS_DOC = "The (optional) value in milliseconds for the initial wait between login attempts to the external"
130:             + " authentication provider."
131:             + LOGIN_EXPONENTIAL_BACKOFF_NOTE;
132: 
133:     public static final String SASL_OAUTHBEARER_JWT_RETRIEVER_CLASS = "sasl.oauthbearer.jwt.retriever.class";
134:     public static final String DEFAULT_SASL_OAUTHBEARER_JWT_RETRIEVER_CLASS = "org.apache.kafka.common.security.oauthbearer.DefaultJwtRetriever";
135:     public static final String SASL_OAUTHBEARER_JWT_RETRIEVER_CLASS_DOC = "<p>The fully-qualified class name of a <code>JwtRetriever</code> implementation used to"
136:         + " request tokens from the identity provider.</p>"
137:         + "<p>The default configuration value represents a class that maintains backward compatibility with previous versions of"
138:         + " Apache Kafka. The default implementation uses the configuration to determine which concrete implementation to create."
139:         + "<p>Other implementations that are provided include:</p>"
140:         + "<ul>"
141:         + "<li><code>org.apache.kafka.common.security.oauthbearer.ClientCredentialsJwtRetriever</code></li>"
142:         + "<li><code>org.apache.kafka.common.security.oauthbearer.DefaultJwtRetriever</code></li>"
143:         + "<li><code>org.apache.kafka.common.security.oauthbearer.FileJwtRetriever</code></li>"
144:         + "<li><code>org.apache.kafka.common.security.oauthbearer.JwtBearerJwtRetriever</code></li>"
145:         + "</ul>";
146: 
147:     public static final String SASL_OAUTHBEARER_JWT_VALIDATOR_CLASS = "sasl.oauthbearer.jwt.validator.class";
148:     public static final String DEFAULT_SASL_OAUTHBEARER_JWT_VALIDATOR_CLASS = "org.apache.kafka.common.security.oauthbearer.DefaultJwtValidator";
149:     public static final String SASL_OAUTHBEARER_JWT_VALIDATOR_CLASS_DOC = "<p>The fully-qualified class name of a <code>JwtValidator</code> implementation used to"
150:         + " validate the JWT from the identity provider.</p>"
151:         + "<p>The default validator (<code>org.apache.kafka.common.security.oauthbearer.DefaultJwtValidator</code>) maintains backward compatibility with previous"
152:         + " versions of Apache Kafka. The default validator uses configuration to determine which concrete implementation to create."
153:         + "<p>The built-in <code>JwtValidator</code> implementations are:</p>"
154:         + "<ul>"
155:         + "<li><code>org.apache.kafka.common.security.oauthbearer.BrokerJwtValidator</code></li>"
156:         + "<li><code>org.apache.kafka.common.security.oauthbearer.ClientJwtValidator</code></li>"
157:         + "<li><code>org.apache.kafka.common.security.oauthbearer.DefaultJwtValidator</code></li>"
158:         + "</ul>";
