160:     public static final String SASL_OAUTHBEARER_SCOPE = "sasl.oauthbearer.scope";
161:     public static final String SASL_OAUTHBEARER_SCOPE_DOC = "<p>This is the level of access a client application is granted to a resource or API which is"
162:         + " included in the token request. If provided, it should match one or more scopes configured in the identity provider.</p>"
163:         + "<p>"
164:         + "The scope was previously stored as part of the <code>sasl.jaas.config</code> configuration with the key <code>scope</code>."
165:         + " For backward compatibility, the <code>scope</code> JAAS option can still be used, but it is deprecated and will be removed in a future version."
166:         + "</p>"
167:         + "<p>Order of precedence:</p>"
168:         + "<ul>"
169:         + "<li><code>sasl.oauthbearer.scope</code> from configuration</li>"
170:         + "<li><code>scope</code> from JAAS</li>"
171:         + "</ul>";
172: 
173:     public static final String SASL_OAUTHBEARER_CLIENT_CREDENTIALS_CLIENT_ID = "sasl.oauthbearer.client.credentials.client.id";
174:     public static final String SASL_OAUTHBEARER_CLIENT_CREDENTIALS_CLIENT_ID_DOC = "<p>The ID (defined in/by the OAuth identity provider) to identify the client" +
175:         " requesting the token.</p>"
176:         + "<p>"
177:         + "The client ID was previously stored as part of the <code>sasl.jaas.config</code> configuration with the key <code>clientId</code>."
178:         + " For backward compatibility, the <code>clientId</code> JAAS option can still be used, but it is deprecated and will be removed in a future version."
179:         + "</p>"
180:         + "<p>Order of precedence:</p>"
181:         + "<ul>"
182:         + "<li><code>sasl.oauthbearer.client.credentials.client.id</code> from configuration</li>"
183:         + "<li><code>clientId</code> from JAAS</li>"
184:         + "</ul>";
185: 
186:     public static final String SASL_OAUTHBEARER_CLIENT_CREDENTIALS_CLIENT_SECRET = "sasl.oauthbearer.client.credentials.client.secret";
187:     public static final String SASL_OAUTHBEARER_CLIENT_CREDENTIALS_CLIENT_SECRET_DOC = "<p>The secret (defined by either the user or preassigned, depending on the"
188:         + " identity provider) of the client requesting the token.</p>"
189:         + "<p>"
190:         + "The client secret was previously stored as part of the <code>sasl.jaas.config</code> configuration with the key <code>clientSecret</code>."
191:         + " For backward compatibility, the <code>clientSecret</code> JAAS option can still be used, but it is deprecated and will be removed in a future version."
192:         + "</p>"
193:         + "<p>Order of precedence:</p>"
194:         + "<ul>"
195:         + "<li><code>sasl.oauthbearer.client.credentials.client.secret</code> from configuration</li>"
196:         + "<li><code>clientSecret</code> from JAAS</li>"
197:         + "</ul>";
