199:     private static final String ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE = "<p><em>Note</em>: If a value for <code>sasl.oauthbearer.assertion.file</code> is provided,"
200:         + " this configuration will be ignored.</p>";
201: 
202:     public static final String SASL_OAUTHBEARER_ASSERTION_ALGORITHM = "sasl.oauthbearer.assertion.algorithm";
203:     public static final String DEFAULT_SASL_OAUTHBEARER_ASSERTION_ALGORITHM = "RS256";
204:     public static final String SASL_OAUTHBEARER_ASSERTION_ALGORITHM_DOC = "<p>The algorithm the Apache Kafka client should use to sign the assertion sent"
205:         + " to the identity provider. It is also used as the value of the OAuth <code>alg</code> (Algorithm) header in the JWT assertion.</p>"
206:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
207: 
208:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_AUD = "sasl.oauthbearer.assertion.claim.aud";
209:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_AUD_DOC = "<p>The JWT <code>aud</code> (Audience) claim which will be included in the "
210:         + " client JWT assertion created locally.</p>"
211:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
212: 
213:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_EXP_SECONDS = "sasl.oauthbearer.assertion.claim.exp.seconds";
214:     public static final int DEFAULT_SASL_OAUTHBEARER_ASSERTION_CLAIM_EXP_SECONDS = 300;
215:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_EXP_SECONDS_DOC = "<p>The number of seconds <em>in the future</em> for which the JWT is valid."
216:         + " The value is used to determine the JWT <code>exp</code> (Expiration) claim based on the current system time when the JWT is created.</p>"
217:         + "<p>The formula to generate the <code>exp</code> claim is very simple:</p>"
218:         + "<pre>"
219:         + "Let:\n\n"
220:         + "  x = the current timestamp in seconds, on client\n"
221:         + "  y = the value of this configuration\n"
222:         + "\n"
223:         + "Then:\n\n"
224:         + "  exp = x + y\n"
225:         + "</pre>"
226:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
227: 
228:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_ISS = "sasl.oauthbearer.assertion.claim.iss";
229:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_ISS_DOC = "<p>The value to be used as the <code>iss</code> (Issuer) claim which will be included in the"
230:         + " client JWT assertion created locally.</p>"
231:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
232: 
233:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_JTI_INCLUDE = "sasl.oauthbearer.assertion.claim.jti.include";
234:     public static final boolean DEFAULT_SASL_OAUTHBEARER_ASSERTION_CLAIM_JTI_INCLUDE = false;
235:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_JTI_INCLUDE_DOC = "<p>Flag that determines if the JWT assertion should generate a unique ID for the"
236:         + " JWT and include it in the <code>jti</code> (JWT ID) claim.</p>"
237:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
238: 
239:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_NBF_SECONDS = "sasl.oauthbearer.assertion.claim.nbf.seconds";
240:     public static final int DEFAULT_SASL_OAUTHBEARER_ASSERTION_CLAIM_NBF_SECONDS = 60;
241:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_NBF_SECONDS_DOC = "<p>The number of seconds <em>in the past</em> from which the JWT is valid."
242:         + " The value is used to determine the JWT <code>nbf</code> (Not Before) claim based on the current system time when the JWT is created.</p>"
243:         + "<p>The formula to generate the <code>nbf</code> claim is very simple:</p>"
244:         + "<pre>"
245:         + "Let:\n\n"
246:         + "  x = the current timestamp in seconds, on client\n"
247:         + "  y = the value of this configuration\n"
248:         + "\n"
249:         + "Then:\n\n"
250:         + "  nbf = x - y\n"
251:         + "</pre>"
252:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
253: 
254:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_SUB = "sasl.oauthbearer.assertion.claim.sub";
255:     public static final String SASL_OAUTHBEARER_ASSERTION_CLAIM_SUB_DOC = "<p>The value to be used as the <code>sub</code> (Subject) claim which will be included in the"
256:         + " client JWT assertion created locally.</p>"
257:         + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;
258: 
259:     public static final String SASL_OAUTHBEARER_ASSERTION_FILE = "sasl.oauthbearer.assertion.file";
260:     public static final String SASL_OAUTHBEARER_ASSERTION_FILE_DOC = "<p>File that contains a <em>pre-generated</em> JWT assertion.</p>"
261:         + "<p>The underlying implementation caches the file contents to avoid the performance hit of loading the file on each access. The caching mechanism will detect when"
262:         + "the file changes to allow for the file to be reloaded on modifications. This allows for &quot;live&quot; assertion rotation without restarting the Kafka client.</p>"
263:         + "<p>The file contains the assertion in the serialized, three part JWT format:</p>"
264:         + "<ol>"
265:         + "<li>The <em>header</em> section is a base 64-encoded JWT header that contains values like <code>alg</code> (Algorithm),"
266:         + " <code>typ</code> (Type, always the literal value <code>JWT</code>), etc.</li>"
267:         + "<li>The <em>payload</em> section includes the base 64-encoded set of JWT claims, such as <code>aud</code> (Audience), <code>iss</code> (Issuer),"
268:         + " <code>sub</code> (Subject), etc.</li>"
269:         + "<li>The <em>signature</em> section is the concatenated <em>header</em> and <em>payload</em> sections that was signed using a private key</li>"
270:         + "</ol>"
271:         + "<p>See <a href=\"https://datatracker.ietf.org/doc/html/rfc7519\">RFC 7519</a> and <a href=\"https://datatracker.ietf.org/doc/html/rfc7515\">RFC 7515</a>"
