104:     public SaslChannelBuilder(ConnectionMode connectionMode,
105:                               Map<String, JaasContext> jaasContexts,
106:                               SecurityProtocol securityProtocol,
107:                               ListenerName listenerName,
108:                               boolean isInterBrokerListener,
109:                               String clientSaslMechanism,
110:                               CredentialCache credentialCache,
111:                               DelegationTokenCache tokenCache,
112:                               String sslClientAuthOverride,
113:                               Time time,
114:                               LogContext logContext,
115:                               Function<Short, ApiVersionsResponse> apiVersionSupplier) {
116:         this.connectionMode = connectionMode;
117:         this.jaasContexts = jaasContexts;
118:         this.loginManagers = new HashMap<>(jaasContexts.size());
119:         this.subjects = new HashMap<>(jaasContexts.size());
120:         this.securityProtocol = securityProtocol;
121:         this.listenerName = listenerName;
122:         this.isInterBrokerListener = isInterBrokerListener;
123:         this.clientSaslMechanism = clientSaslMechanism;
124:         this.credentialCache = credentialCache;
125:         this.tokenCache = tokenCache;
126:         this.sslClientAuthOverride = sslClientAuthOverride;
127:         this.saslCallbackHandlers = new HashMap<>();
128:         this.connectionsMaxReauthMsByMechanism = new HashMap<>();
129:         this.time = time;
130:         this.logContext = logContext;
131:         this.log = logContext.logger(getClass());
132:         this.apiVersionSupplier = apiVersionSupplier;
