17: package org.apache.kafka.common.security.scram.internals;
18: 
19: import org.apache.kafka.common.security.auth.AuthenticateCallbackHandler;
20: import org.apache.kafka.common.security.authenticator.CredentialCache;
21: import org.apache.kafka.common.security.scram.ScramCredential;
22: import org.apache.kafka.common.security.scram.ScramCredentialCallback;
23: import org.apache.kafka.common.security.token.delegation.TokenInformation;
24: import org.apache.kafka.common.security.token.delegation.internals.DelegationTokenCache;
25: import org.apache.kafka.common.security.token.delegation.internals.DelegationTokenCredentialCallback;
26: 
27: import java.util.List;
28: import java.util.Map;
29: 
30: import javax.security.auth.callback.Callback;
31: import javax.security.auth.callback.NameCallback;
32: import javax.security.auth.callback.UnsupportedCallbackException;
33: import javax.security.auth.login.AppConfigurationEntry;
34: 
35: public class ScramServerCallbackHandler implements AuthenticateCallbackHandler {
36: 
37:     private final CredentialCache.Cache<ScramCredential> credentialCache;
38:     private final DelegationTokenCache tokenCache;
39:     private String saslMechanism;
40: 
41:     public ScramServerCallbackHandler(CredentialCache.Cache<ScramCredential> credentialCache,
42:                                       DelegationTokenCache tokenCache) {
43:         this.credentialCache = credentialCache;
44:         this.tokenCache = tokenCache;
45:     }
46: 
47:     @Override
48:     public void configure(Map<String, ?> configs, String mechanism, List<AppConfigurationEntry> jaasConfigEntries) {
49:         this.saslMechanism = mechanism;
50:     }
51: 
52:     @Override
53:     public void handle(Callback[] callbacks) throws UnsupportedCallbackException {
54:         String username = null;
55:         for (Callback callback : callbacks) {
56:             if (callback instanceof NameCallback)
57:                 username = ((NameCallback) callback).getDefaultName();
58:             else if (callback instanceof DelegationTokenCredentialCallback) {
59:                 DelegationTokenCredentialCallback tokenCallback = (DelegationTokenCredentialCallback) callback;
60:                 tokenCallback.scramCredential(tokenCache.credential(saslMechanism, username));
61:                 tokenCallback.tokenOwner(tokenCache.owner(username));
62:                 TokenInformation tokenInfo = tokenCache.token(username);
63:                 if (tokenInfo != null)
64:                     tokenCallback.tokenExpiryTimestamp(tokenInfo.expiryTimestamp());
65:             } else if (callback instanceof ScramCredentialCallback) {
66:                 ScramCredentialCallback sc = (ScramCredentialCallback) callback;
67:                 sc.scramCredential(credentialCache.get(username));
68:             } else
69:                 throw new UnsupportedCallbackException(callback);
70:         }
71:     }
72: 
73:     @Override
74:     public void close() {
75:     }
76: }
